import{_ as l,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"云平台和多云","description":"","frontmatter":{},"headers":[],"relativePath":"zh/infrastructure/cloud.md","filePath":"zh/infrastructure/cloud.md"}'),o={name:"zh/infrastructure/cloud.md"};function e(s,a,n,h,d,u){return t(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="云平台和多云" tabindex="-1">云平台和多云 <a class="header-anchor" href="#云平台和多云" aria-label="Permalink to &quot;云平台和多云&quot;">​</a></h1><h2 id="云计算模型" tabindex="-1">云计算模型 <a class="header-anchor" href="#云计算模型" aria-label="Permalink to &quot;云计算模型&quot;">​</a></h2><h3 id="iaas-基础设施即服务" tabindex="-1">IaaS（基础设施即服务） <a class="header-anchor" href="#iaas-基础设施即服务" aria-label="Permalink to &quot;IaaS（基础设施即服务）&quot;">​</a></h3><p>原始计算、存储和网络资源：</p><ul><li>示例：EC2（AWS）、Compute Engine（GCP）、VMs（Azure）</li><li>使用场景：完全控制、自定义配置</li></ul><h3 id="paas-平台即服务" tabindex="-1">PaaS（平台即服务） <a class="header-anchor" href="#paas-平台即服务" aria-label="Permalink to &quot;PaaS（平台即服务）&quot;">​</a></h3><p>运行应用的托管环境：</p><ul><li>示例：Heroku、Cloud Run、App Engine</li><li>使用场景：专注于代码，而不是基础设施</li></ul><h3 id="saas-软件即服务" tabindex="-1">SaaS（软件即服务） <a class="header-anchor" href="#saas-软件即服务" aria-label="Permalink to &quot;SaaS（软件即服务）&quot;">​</a></h3><p>完全托管的应用：</p><ul><li>示例：Salesforce、Gmail、GitHub</li><li>使用场景：无需托管即可使用</li></ul><h2 id="aws-亚马逊网络服务" tabindex="-1">AWS（亚马逊网络服务） <a class="header-anchor" href="#aws-亚马逊网络服务" aria-label="Permalink to &quot;AWS（亚马逊网络服务）&quot;">​</a></h2><p>最大的云提供商，提供最广泛的服务范围。</p><h3 id="计算" tabindex="-1">计算 <a class="header-anchor" href="#计算" aria-label="Permalink to &quot;计算&quot;">​</a></h3><ul><li><strong>EC2</strong>：具有完全控制的虚拟机</li><li><strong>Lambda</strong>：无服务器函数</li><li><strong>ECS</strong>：容器编排（Kubernetes 的替代品）</li><li><strong>EKS</strong>：托管的 Kubernetes</li></ul><h3 id="存储" tabindex="-1">存储 <a class="header-anchor" href="#存储" aria-label="Permalink to &quot;存储&quot;">​</a></h3><ul><li><strong>S3</strong>：对象存储（文件、备份、静态内容）</li><li><strong>EBS</strong>：块存储（数据库、卷）</li><li><strong>EFS</strong>：网络文件系统（共享存储）</li></ul><h3 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h3><ul><li><strong>RDS</strong>：托管关系数据库（PostgreSQL、MySQL、MariaDB）</li><li><strong>DynamoDB</strong>：NoSQL 键值存储</li><li><strong>ElastiCache</strong>：内存缓存（Redis、Memcached）</li></ul><h3 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h3><ul><li><strong>VPC</strong>：虚拟私有云</li><li><strong>ELB/ALB</strong>：负载均衡器</li><li><strong>Route 53</strong>：DNS 服务</li><li><strong>CloudFront</strong>：CDN</li></ul><h3 id="devops-服务" tabindex="-1">DevOps 服务 <a class="header-anchor" href="#devops-服务" aria-label="Permalink to &quot;DevOps 服务&quot;">​</a></h3><ul><li><strong>CodePipeline</strong>：CI/CD 编排</li><li><strong>CodeBuild</strong>：构建服务</li><li><strong>CodeDeploy</strong>：部署自动化</li><li><strong>CloudFormation</strong>：基础设施即代码</li></ul><h2 id="google-cloud-platform-gcp" tabindex="-1">Google Cloud Platform（GCP） <a class="header-anchor" href="#google-cloud-platform-gcp" aria-label="Permalink to &quot;Google Cloud Platform（GCP）&quot;">​</a></h2><p>以数据处理和机器学习而闻名。</p><h3 id="计算-1" tabindex="-1">计算 <a class="header-anchor" href="#计算-1" aria-label="Permalink to &quot;计算&quot;">​</a></h3><ul><li><strong>Compute Engine</strong>：虚拟机</li><li><strong>App Engine</strong>：托管应用托管</li><li><strong>Cloud Run</strong>：无服务器容器</li><li><strong>GKE</strong>：托管的 Kubernetes</li></ul><h3 id="存储-1" tabindex="-1">存储 <a class="header-anchor" href="#存储-1" aria-label="Permalink to &quot;存储&quot;">​</a></h3><ul><li><strong>Cloud Storage</strong>：对象存储</li><li><strong>Persistent Disk</strong>：块存储</li><li><strong>Filestore</strong>：网络文件系统</li></ul><h3 id="数据库-1" tabindex="-1">数据库 <a class="header-anchor" href="#数据库-1" aria-label="Permalink to &quot;数据库&quot;">​</a></h3><ul><li><strong>Cloud SQL</strong>：托管数据库</li><li><strong>Cloud Datastore</strong>：NoSQL 数据库</li><li><strong>Bigtable</strong>：大规模 NoSQL</li><li><strong>Firestore</strong>：文档数据库</li></ul><h3 id="独特优势" tabindex="-1">独特优势 <a class="header-anchor" href="#独特优势" aria-label="Permalink to &quot;独特优势&quot;">​</a></h3><ul><li><strong>BigQuery</strong>：数据仓库和分析</li><li><strong>Cloud AI/ML</strong>：机器学习服务</li><li><strong>Dataflow</strong>：流和批处理</li></ul><h2 id="microsoft-azure" tabindex="-1">Microsoft Azure <a class="header-anchor" href="#microsoft-azure" aria-label="Permalink to &quot;Microsoft Azure&quot;">​</a></h2><p>强大的企业集成和混合功能。</p><h3 id="计算-2" tabindex="-1">计算 <a class="header-anchor" href="#计算-2" aria-label="Permalink to &quot;计算&quot;">​</a></h3><ul><li><strong>Virtual Machines</strong>：IaaS VMs</li><li><strong>App Service</strong>：托管网络应用</li><li><strong>Container Instances</strong>：无服务器容器</li><li><strong>AKS</strong>：托管的 Kubernetes</li></ul><h3 id="存储-2" tabindex="-1">存储 <a class="header-anchor" href="#存储-2" aria-label="Permalink to &quot;存储&quot;">​</a></h3><ul><li><strong>Blob Storage</strong>：对象存储</li><li><strong>Disk Storage</strong>：块存储</li><li><strong>File Shares</strong>：网络文件系统</li></ul><h3 id="数据库-2" tabindex="-1">数据库 <a class="header-anchor" href="#数据库-2" aria-label="Permalink to &quot;数据库&quot;">​</a></h3><ul><li><strong>Azure SQL</strong>：托管 SQL Server/PostgreSQL</li><li><strong>Cosmos DB</strong>：全球分布式 NoSQL</li><li><strong>Azure Database</strong>：托管 MySQL、PostgreSQL</li></ul><h3 id="独特优势-1" tabindex="-1">独特优势 <a class="header-anchor" href="#独特优势-1" aria-label="Permalink to &quot;独特优势&quot;">​</a></h3><ul><li><strong>Active Directory 集成</strong>：企业安全</li><li><strong>混合云</strong>：无缝的本地集成</li><li><strong>Microsoft Stack 支持</strong>：.NET、Office 365 集成</li></ul><h2 id="选择云提供商" tabindex="-1">选择云提供商 <a class="header-anchor" href="#选择云提供商" aria-label="Permalink to &quot;选择云提供商&quot;">​</a></h2><table tabindex="0"><thead><tr><th>因素</th><th>AWS</th><th>GCP</th><th>Azure</th></tr></thead><tbody><tr><td>市场份额</td><td>最大</td><td>增长</td><td>企业强</td></tr><tr><td>易用性</td><td>陡峭</td><td>中等</td><td>陡峭</td></tr><tr><td>成本</td><td>有竞争力</td><td>有竞争力</td><td>有竞争力</td></tr><tr><td>数据/ML</td><td>好</td><td>优秀</td><td>好</td></tr><tr><td>企业</td><td>成熟</td><td>增长</td><td>优秀</td></tr><tr><td>全球覆盖</td><td>最好</td><td>最好</td><td>好</td></tr></tbody></table><h2 id="多云策略" tabindex="-1">多云策略 <a class="header-anchor" href="#多云策略" aria-label="Permalink to &quot;多云策略&quot;">​</a></h2><h3 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h3><ul><li>避免供应商锁定</li><li>利用提供商优势</li><li>跨云灾难恢复</li><li>不同地区的合规性</li></ul><h3 id="挑战" tabindex="-1">挑战 <a class="header-anchor" href="#挑战" aria-label="Permalink to &quot;挑战&quot;">​</a></h3><ul><li>运维复杂性</li><li>团队技能要求</li><li>成本管理困难</li><li>数据出站成本</li></ul><h3 id="多云工具" tabindex="-1">多云工具 <a class="header-anchor" href="#多云工具" aria-label="Permalink to &quot;多云工具&quot;">​</a></h3><p><strong>Kubernetes</strong></p><ul><li>在任何云提供商上运行</li><li>可移植工作负载</li><li>一致的 API</li></ul><p><strong>Terraform</strong></p><ul><li>云无关的 IaC</li><li>单一配置语言</li></ul><p><strong>多云平台</strong></p><ul><li>HashiCorp Consul：服务网格</li><li>CNCF Stackdriver：可观测性</li></ul><h2 id="成本优化" tabindex="-1">成本优化 <a class="header-anchor" href="#成本优化" aria-label="Permalink to &quot;成本优化&quot;">​</a></h2><h3 id="aws-成本管理" tabindex="-1">AWS 成本管理 <a class="header-anchor" href="#aws-成本管理" aria-label="Permalink to &quot;AWS 成本管理&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 使用 AWS 成本浏览器</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设置预算告警</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 对可预测工作负载使用预留实例</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 对容错工作负载使用 Spot 实例</span></span></code></pre></div><h3 id="成本降低策略" tabindex="-1">成本降低策略 <a class="header-anchor" href="#成本降低策略" aria-label="Permalink to &quot;成本降低策略&quot;">​</a></h3><ol><li><strong>适当调整大小</strong>：使用合适的实例类型</li><li><strong>自动扩展</strong>：扩展未使用的容量</li><li><strong>预留实例</strong>：折扣长期费率</li><li><strong>Spot 实例</strong>：便宜 90%，但可中断</li><li><strong>数据传输</strong>：最小化出站成本</li><li><strong>存储优化</strong>：存档旧数据</li></ol><h2 id="灾难恢复" tabindex="-1">灾难恢复 <a class="header-anchor" href="#灾难恢复" aria-label="Permalink to &quot;灾难恢复&quot;">​</a></h2><h3 id="rto-rpo" tabindex="-1">RTO/RPO <a class="header-anchor" href="#rto-rpo" aria-label="Permalink to &quot;RTO/RPO&quot;">​</a></h3><ul><li><strong>RTO</strong>（恢复时间目标）：最大可接受停机时间</li><li><strong>RPO</strong>（恢复点目标）：最大可接受数据损失</li></ul><h3 id="策略" tabindex="-1">策略 <a class="header-anchor" href="#策略" aria-label="Permalink to &quot;策略&quot;">​</a></h3><p><strong>备份和恢复</strong></p><ul><li>RTO：小时，RPO：小时</li><li>最便宜，最慢</li></ul><p><strong>热备</strong></p><ul><li>RTO：10-15 分钟，RPO：分钟</li><li>最小资源运行</li></ul><p><strong>温备</strong></p><ul><li>RTO：分钟，RPO：秒</li><li>接近完全容量的待机</li></ul><p><strong>双活</strong></p><ul><li>RTO：无，RPO：无</li><li>完全复制，最高成本</li></ul><h2 id="混合云" tabindex="-1">混合云 <a class="header-anchor" href="#混合云" aria-label="Permalink to &quot;混合云&quot;">​</a></h2><p>结合本地和云基础设施：</p><h3 id="aws-outposts" tabindex="-1">AWS Outposts <a class="header-anchor" href="#aws-outposts" aria-label="Permalink to &quot;AWS Outposts&quot;">​</a></h3><ul><li>AWS 基础设施在您的场所</li><li>一致的 API 和工具</li><li>低延迟连接</li></ul><h3 id="azure-stack" tabindex="-1">Azure Stack <a class="header-anchor" href="#azure-stack" aria-label="Permalink to &quot;Azure Stack&quot;">​</a></h3><ul><li>本地 Azure 服务</li><li>一致的体验</li><li>灵活的部署选项</li></ul><h2 id="云中的安全" tabindex="-1">云中的安全 <a class="header-anchor" href="#云中的安全" aria-label="Permalink to &quot;云中的安全&quot;">​</a></h2><ol><li><strong>身份和访问</strong>：IAM 策略、MFA</li><li><strong>网络</strong>：VPCs、防火墙、安全组</li><li><strong>加密</strong>：传输中和静止时</li><li><strong>合规性</strong>：满足监管要求</li><li><strong>监控</strong>：CloudTrail、VPC Flow Logs</li><li><strong>秘密管理</strong>：AWS Secrets Manager、Azure Key Vault</li></ol><h2 id="云原生架构" tabindex="-1">云原生架构 <a class="header-anchor" href="#云原生架构" aria-label="Permalink to &quot;云原生架构&quot;">​</a></h2><h3 id="特征" tabindex="-1">特征 <a class="header-anchor" href="#特征" aria-label="Permalink to &quot;特征&quot;">​</a></h3><ul><li><strong>微服务</strong>：小的、独立的服务</li><li><strong>容器</strong>：便携、轻量级部署</li><li><strong>无服务器</strong>：基于函数的计算</li><li><strong>托管服务</strong>：减少运维负担</li><li><strong>自动扩展</strong>：动态容量调整</li><li><strong>弹性</strong>：优雅处理故障</li></ul>`,85)])])}const b=l(o,[["render",e]]);export{c as __pageData,b as default};
